/*
 * AQA GCSE Biology (8461) — Exam Practice Question Bank
 * All written/exam-style questions with AQA command words and mark schemes.
 * 40 questions per topic, varying from 1-mark to 6-mark questions.
 * Questions that may require a diagram set needsDiagram: true so the practice UI can render a drawing panel.
 */

const BIOLOGY_AQA_GCSE_PRACTICE = {

  /* ─────────────────────────────────────────────────────────── 4.1 Cell Biology */
  '4.1': {
    name: 'Cell Biology',
    questions: [
      { q: 'State the function of the nucleus in a eukaryotic cell.', marks: 1, markScheme: `• Contains genetic material (DNA) / chromosomes which control the activities of the cell (1).` },
      { q: 'State the function of the mitochondria.', marks: 1, markScheme: `• Site of aerobic respiration — release energy for cell processes (1).` },
      { q: 'State the function of the ribosomes.', marks: 1, markScheme: `• Site of protein synthesis (1).` },
      { q: 'State three structures found in a plant cell that are NOT found in an animal cell.', marks: 3, markScheme: `• Cell wall (cellulose) (1); chloroplasts (containing chlorophyll) (1); permanent (large) vacuole (containing cell sap) (1).` },
      { q: 'State two differences between a prokaryotic and a eukaryotic cell.', marks: 2, markScheme: `• Prokaryotic cells have no true nucleus — genetic material is a single loop of DNA in the cytoplasm (+ plasmids) (1). Eukaryotic have a nucleus (1).\n• Prokaryotic cells are much smaller (~0.1–5 μm) than eukaryotic cells (~10–100 μm) (1).\n• Prokaryotic cells have no membrane-bound organelles (1). (Any 2.)` },
      { q: 'Describe two ways a sperm cell is adapted to its function.', marks: 2, markScheme: `• Tail/flagellum for swimming to egg (1).\n• Many mitochondria for energy (1). (Also accept: acrosome with enzymes; haploid nucleus; streamlined.)` },
      { q: 'Describe how a root hair cell is adapted for absorbing water and mineral ions.', marks: 3, markScheme: `• Long projection/hair increases surface area for absorption (1).\n• Thin cell wall / membrane — short diffusion distance (1).\n• Many mitochondria release energy for active transport of mineral ions against a concentration gradient (1).` },
      { q: 'Define diffusion and give one example in a living organism.', marks: 2, markScheme: `• Net movement of particles from a higher to a lower concentration down a gradient (1).\n• Example: O₂ diffuses from alveoli into blood; CO₂ diffuses from blood to alveoli (1).` },
      { q: 'Define osmosis.', marks: 2, markScheme: `• Net movement of water molecules (1) across a partially permeable membrane from a dilute solution (high water potential) to a more concentrated solution (low water potential) (1).` },
      { q: 'Describe what happens to an animal cell placed in distilled water.', marks: 3, markScheme: `• Water moves into the cell by osmosis (1) because the cytoplasm has a lower water potential than pure water (1). The cell swells and may burst (lysis) because it has no cell wall to resist (1).` },
      { q: 'Explain why a plant cell placed in strong sucrose solution becomes plasmolysed.', marks: 3, markScheme: `• Sucrose solution is more concentrated than the cytoplasm (lower water potential) (1). Water leaves the cell by osmosis (1). The cell membrane pulls away from the cell wall as the protoplast shrinks (plasmolysis) (1).` },
      { q: 'State one substance that is moved into a cell by active transport.', marks: 1, markScheme: `• Mineral ions (e.g. nitrate ions into root hair cells) / glucose from the small intestine into the blood (when blood glucose is higher) (1).` },
      { q: 'Explain the difference between diffusion and active transport.', marks: 3, markScheme: `• Diffusion is movement down a concentration gradient (high → low) and does not require energy (1).\n• Active transport is against a gradient (low → high) (1) and requires energy from respiration (ATP) and carrier proteins (1).` },
      { q: 'Describe the stages of the cell cycle, including mitosis.', marks: 5, markScheme: `• Interphase: cell grows, organelles are copied, DNA replicates (each chromosome becomes two sister chromatids) (1).\n• Chromosomes condense and become visible (1).\n• Chromosomes line up at the equator and are pulled apart to opposite poles (1).\n• Two new nuclei form (1).\n• Cytoplasm and cell membrane divide (cytokinesis) forming two identical diploid daughter cells (1).` },
      { q: 'State two functions of cell division by mitosis in a multicellular organism.', marks: 2, markScheme: `• Growth/development (1).\n• Repair of damaged tissue / replacement of worn-out cells (1). (Also accept: asexual reproduction.)` },
      { q: 'Define a "stem cell" and state one source in an adult human.', marks: 2, markScheme: `• An undifferentiated cell capable of dividing to form more of the same type and of differentiating into specialised cells (1).\n• Source: bone marrow (1). (Also accept: umbilical cord blood.)` },
      { q: 'Describe two possible medical uses of stem cells.', marks: 2, markScheme: `• Treating paralysis by replacing nerve cells (1).\n• Treating type 1 diabetes by producing insulin-making pancreatic cells (1). (Also accept: treating eye conditions; leukaemia with bone marrow transplants.)` },
      { q: 'State one ethical and one scientific objection to the use of embryonic stem cells.', marks: 2, markScheme: `• Ethical: destroying human embryos (1).\n• Scientific: risk of rejection / tumour formation / transmission of viruses (1).` },
      { q: 'Describe what happens in therapeutic cloning.', marks: 3, markScheme: `• The nucleus of a patient\'s body cell is removed and transferred into an empty egg cell (1).\n• The egg is stimulated to divide, producing an embryo with cells genetically identical to the patient (1).\n• Stem cells from the embryo can be used to grow tissues that will not be rejected (1).` },
      { q: 'Explain why meristem tissue in plants is important for horticulture.', marks: 3, markScheme: `• Meristem tissue contains undifferentiated cells that divide by mitosis (1).\n• It allows production of clones of rare/desirable plants (1).\n• Produces disease-free identical plants quickly and cheaply (1).` },
      { q: 'An image of a cell measures 40 mm. The real cell is 20 μm wide. Calculate the magnification (1 mm = 1000 μm).', marks: 2, markScheme: `• Convert: 40 mm = 40 000 μm (1).\n• Magnification = image size ÷ real size = 40 000 ÷ 20 = ×2000 (1).` },
      { q: 'Compare light and electron microscopes.', marks: 4, markScheme: `• Light microscope uses light; electron microscope uses a beam of electrons (1).\n• Light microscope has lower magnification (up to ×1500) and lower resolution (~200 nm); electron microscope has much higher magnification (×2 000 000) and resolution (~0.2 nm) (1).\n• Electron microscope allows smaller structures (ribosomes, mitochondria internal detail) to be seen (1).\n• Light microscope is cheaper and can view living cells; electron microscope is expensive and samples must be specially prepared (1).`, needsDiagram: false },
      { q: 'A student viewed a cell at ×400 and measured it as 30 mm. Calculate the real length of the cell in μm.', marks: 2, markScheme: `• Real = image ÷ magnification = 30 mm ÷ 400 = 0.075 mm (1).\n• 0.075 mm = 75 μm (1).` },
      { q: 'Explain why bacteria divide so rapidly under favourable conditions.', marks: 3, markScheme: `• Bacteria reproduce by binary fission — simple cell division (1).\n• In favourable conditions (warm, moist, nutrient-rich), they can divide every 20 minutes (1).\n• 1 bacterium can become 8 in 1 hour and millions in a day if conditions remain favourable (1).` },
      { q: 'State three conditions needed for aseptic technique when culturing bacteria in a school lab.', marks: 3, markScheme: `• Sterilise equipment (e.g. petri dishes, loops) before use (autoclaving or flaming) (1).\n• Work near a Bunsen flame / sterilise air to prevent contamination (1).\n• Secure the lid with tape (not fully sealed — aerobic conditions); incubate at a maximum of 25 °C in schools to reduce the risk of pathogens growing (1).` },
      { q: 'Describe an investigation to test the effectiveness of different antibiotics on bacterial growth.', marks: 6, markScheme: `• Use a sterile agar plate and spread a lawn of bacteria across the surface using a sterile spreader (1).\n• Place several paper discs soaked in different antibiotics (and a control disc of water) onto the plate (1).\n• Incubate at 25 °C for 24–48 hours (1).\n• Measure the diameter of the clear "zone of inhibition" around each disc (1).\n• Calculate area using πr² (1).\n• The larger the zone, the more effective the antibiotic; compare to control (1).`, needsDiagram: true },
      { q: 'A student places 5 potato cylinders in sucrose solutions of 0, 0.2, 0.4, 0.6, 0.8 and 1.0 mol/dm³ and measures the percentage change in mass. Explain how the data can be used to estimate the concentration of solute in potato cell sap.', marks: 4, markScheme: `• Plot % change in mass on y-axis vs sucrose concentration on x-axis (1).\n• Draw a line of best fit (1).\n• The concentration at which % change = 0 is the isotonic point: the solute concentration inside the cell equals that outside (1).\n• Read the x-axis value at y = 0 (usually around 0.25–0.35 mol/dm³) (1).`, needsDiagram: true },
      { q: 'Describe why specialised cells differentiate during development.', marks: 3, markScheme: `• As multicellular organisms develop, different cells express different genes (1).\n• This causes them to become specialised in structure to carry out a particular function (1).\n• Specialised cells work together in tissues and organs, making the organism more efficient overall (1).` },
      { q: 'Explain why most specialised animal cells can no longer divide once differentiated, but many plant cells can.', marks: 3, markScheme: `• In animals, most cells differentiate early and lose the ability to divide (1); only a few (stem cells in marrow, skin, gut) retain this ability (1).\n• Plant cells generally retain the ability to differentiate into any cell type and regions of meristem actively divide throughout the plant\'s life (1).` },
      { q: 'A student measured the diameter of a red blood cell on a micrograph as 7 mm at ×1000 magnification. Calculate its real diameter.', marks: 2, markScheme: `• Real = image / magnification = 7 mm ÷ 1000 = 0.007 mm (1).\n• 0.007 mm = 7 μm (1).` },
      { q: 'Describe the structure and function of cellulose cell walls in plant cells.', marks: 3, markScheme: `• Cellulose cell walls are made of long chains of cellulose fibres arranged in a mesh (1).\n• They are strong yet permeable to water and dissolved substances (1).\n• They keep the cell rigid and provide support for the plant (especially when fully turgid) (1).` },
      { q: 'Explain why nerve cells are long and branched.', marks: 2, markScheme: `• Long axons allow rapid transmission of impulses over long distances (1).\n• Branched dendrites allow connections with many other cells at synapses (1).` },
      { q: 'Describe how you would use a light microscope to view a prepared slide.', marks: 5, markScheme: `• Place the slide on the stage and secure it (1).\n• Use the lowest-power objective first (1).\n• Use the coarse focus knob to move the stage close to the objective, then look through the eyepiece and turn the coarse focus to move the stage away until the image is roughly in focus (1).\n• Use the fine focus to get a sharp image (1).\n• Switch to higher magnification; refocus using fine adjustment only (1).` },
      { q: 'Explain the advantage of a large surface-area-to-volume ratio for diffusion.', marks: 3, markScheme: `• A larger surface area provides more space for substances to diffuse across (1).\n• A smaller volume means shorter diffusion distances inside the cell (1).\n• Both maximise the rate of exchange, so single cells (small volume, large SA:V) rely on diffusion, while larger organisms need specialised exchange surfaces (1).` },
      { q: 'Calculate the surface-area-to-volume ratio of a cube of side 3 cm.', marks: 2, markScheme: `• Surface area = 6 × (3 × 3) = 54 cm² (1).\n• Volume = 3³ = 27 cm³; SA:V = 54:27 = 2:1 (1).` },
      { q: 'Describe how you would estimate the number of cells in a field of view using an eyepiece graticule and prepare a drawing.', marks: 4, markScheme: `• Calibrate the eyepiece graticule using a stage micrometer at the required magnification (1).\n• View the sample and count the number of cells that fit along a measured distance of the graticule (1).\n• Estimate the width of one cell (1).\n• Record the magnification with a labelled scientific drawing using a sharp pencil, clear lines, no shading, and a scale bar (1).`, needsDiagram: true },
      { q: 'Explain why single-celled organisms do not need specialised exchange surfaces.', marks: 2, markScheme: `• They have a large surface-area-to-volume ratio (1).\n• Diffusion alone is sufficient to supply nutrients and remove waste across the cell membrane (1).` },
      { q: 'Describe three factors that affect the rate of diffusion across a membrane.', marks: 3, markScheme: `• Concentration gradient — steeper gradient = faster diffusion (1).\n• Surface area — larger SA = faster diffusion (1).\n• Temperature — higher T = more kinetic energy, faster diffusion / thickness of membrane (1).` },
      { q: 'Describe the stages you would follow to make a biological drawing of an onion cell.', marks: 4, markScheme: `• Prepare a slide: peel a thin layer of onion epidermis, place on a slide, add iodine and a cover slip (1).\n• View under low then high power (1).\n• Draw using a sharp pencil, clean continuous lines (no shading), accurate proportions (1).\n• Label structures (nucleus, cytoplasm, cell wall, vacuole) with straight lines and include magnification and a scale bar (1).`, needsDiagram: true },
      { q: '"Cellulose is the most abundant organic molecule on Earth." Evaluate the importance of cellulose for plants AND humans.', marks: 4, markScheme: `• For plants: cellulose cell walls provide mechanical support and prevent cells bursting under osmotic pressure (1). Arranged in layers for extra strength (1).\n• For humans: cellulose is a key component of dietary fibre — we cannot digest it but it helps bowel function (1). Cotton, paper and many natural textiles are made of cellulose fibres (1).` },
    ]
  },

  /* ─────────────────────────────────────────────────────────── 4.2 Organisation */
  '4.2': {
    name: 'Organisation',
    questions: [
      { q: 'State three features of enzymes.', marks: 3, markScheme: `• Biological catalysts (1) — speed up reactions without being used up.\n• Proteins (1).\n• Specific — each catalyses one type of reaction (active site complementary to substrate) (1).` },
      { q: 'Explain the lock-and-key model of enzyme action.', marks: 3, markScheme: `• The substrate has a specific 3D shape complementary to the active site of the enzyme (1).\n• The substrate fits into the active site like a key into a lock, forming an enzyme–substrate complex (1).\n• The reaction occurs and products leave the active site, which is unchanged and can be re-used (1).`, needsDiagram: true },
      { q: 'Describe the effect of temperature on enzyme activity.', marks: 4, markScheme: `• As temperature rises, molecules have more kinetic energy, leading to more successful collisions — rate increases (1).\n• Rate reaches a maximum at the optimum temperature (1).\n• Above the optimum, bonds in the enzyme break, changing the 3D shape of the active site (1).\n• The enzyme is denatured; substrate no longer fits — rate falls sharply to zero (1).`, needsDiagram: true },
      { q: 'Describe the effect of pH on enzyme activity.', marks: 3, markScheme: `• Each enzyme has an optimum pH (e.g. pepsin ~2; amylase ~7; trypsin ~8) (1).\n• Moving away from the optimum alters charged groups in the active site, changing its shape; substrate no longer fits (1).\n• Extreme pH denatures the enzyme and activity ceases (1).` },
      { q: 'State the site of production and optimum pH of: pepsin, amylase.', marks: 2, markScheme: `• Pepsin — stomach; optimum pH ~2 (acidic) (1).\n• Amylase — salivary glands and pancreas; optimum pH ~7 (near neutral) (1).` },
      { q: 'Describe how you could test a food sample for (a) starch and (b) reducing sugars.', marks: 4, markScheme: `• Starch: add a few drops of iodine solution; turns from yellow/brown to blue-black if starch present (1) (1 for correct colour change).\n• Reducing sugars: add Benedict\'s reagent and heat in a water bath at 60–80 °C (1). A blue solution turns green → yellow → orange → brick-red precipitate if reducing sugar present (1).` },
      { q: 'Describe the test for proteins and state the colour change.', marks: 2, markScheme: `• Add biuret reagent (sodium hydroxide + dilute copper sulfate) to the food sample (1).\n• Positive result: blue → purple/violet colour (1).` },
      { q: 'Describe the test for lipids (emulsion/Sudan III).', marks: 2, markScheme: `• Emulsion test: add ethanol, shake, add water. A cloudy white emulsion indicates lipid (1). (Or) Sudan III stains lipids red (1).` },
      { q: 'Describe the route blood takes from the vena cava to the aorta.', marks: 4, markScheme: `• Vena cava → right atrium → (through tricuspid valve) right ventricle (1) → pulmonary artery → lungs (1) → pulmonary vein → left atrium → (through bicuspid valve) left ventricle (1) → aorta (1).`, needsDiagram: true },
      { q: 'Explain why the left ventricle has a thicker wall than the right ventricle.', marks: 2, markScheme: `• The left ventricle pumps blood around the entire body, requiring high pressure (1).\n• The right ventricle only pumps to the nearby lungs at lower pressure (1).` },
      { q: 'Describe the function of the four main valves in the heart.', marks: 2, markScheme: `• Atrioventricular valves (tricuspid, bicuspid/mitral) prevent backflow from the ventricles into the atria when ventricles contract (1).\n• Semilunar valves (aortic, pulmonary) prevent backflow from arteries back into the ventricles when ventricles relax (1).` },
      { q: 'Describe how a stent treats coronary heart disease.', marks: 3, markScheme: `• A stent is a mesh tube (1).\n• It is inserted into a narrowed coronary artery, typically via a balloon catheter, then expanded (1).\n• The stent holds the artery open, allowing blood to flow freely to the heart muscle (1).` },
      { q: 'Evaluate the use of statins compared to stents for treating coronary heart disease.', marks: 6, markScheme: `• Statins — drugs that lower LDL cholesterol (1); slow plaque development and reduce risk of further narrowing (1); must be taken for life, side effects e.g. muscle pain, liver problems (1).\n• Stents — mesh tubes providing an immediate physical solution (1); surgical procedure, risks of infection, damage, blood clots, may need replacement (1).\n• Conclusion: stents are used for severe acute blockage; statins may prevent need for surgery and are more suitable as long-term preventative care. Combined use is common (1).` },
      { q: 'Describe two non-communicable diseases associated with risk factors.', marks: 2, markScheme: `• Cardiovascular disease — risk factors: smoking, high-fat/high-salt diet, obesity, inactivity (1).\n• Type 2 diabetes — risk factor: obesity and inactivity (1). (Also accept: some cancers — smoking, alcohol, UV exposure.)` },
      { q: 'State the difference between benign and malignant tumours.', marks: 2, markScheme: `• Benign tumours grow in one place, do not invade other tissues, usually not dangerous (1).\n• Malignant tumours grow and cells break off, spread via blood to form secondary tumours in other parts of the body (metastasis) — cancerous (1).` },
      { q: 'Describe how palisade mesophyll cells are adapted for photosynthesis.', marks: 3, markScheme: `• Located near the upper surface of leaf, close to light (1).\n• Column-shaped — tightly packed to absorb maximum light (1).\n• Contain many chloroplasts for photosynthesis (1).` },
      { q: 'Describe how the structure of xylem is adapted to its function.', marks: 3, markScheme: `• Dead cells fused end-to-end to form hollow tubes (1).\n• Walls strengthened by lignin, providing support and preventing collapse under tension (1).\n• Narrow diameter — allows water to be drawn up by transpiration stream due to capillary action / cohesion-tension (1).` },
      { q: 'Describe how the structure of phloem is adapted to its function.', marks: 3, markScheme: `• Living sieve tube cells with sieve plates (porous end walls) — allow dissolved sugars to flow (1).\n• Adjacent companion cells provide energy from respiration (many mitochondria) for active loading of sugars (1).\n• Dissolved sucrose is transported from source (leaves) to sinks (roots, fruits, storage organs) by translocation (1).` },
      { q: 'Explain the role of stomata and guard cells in a leaf.', marks: 3, markScheme: `• Stomata are small pores (mainly on the lower surface) that allow gas exchange — CO₂ in for photosynthesis, O₂ and water vapour out (1).\n• Each stoma is flanked by a pair of guard cells (1).\n• When guard cells are turgid, stomata open; when water is lost they become flaccid and stomata close, reducing further water loss (1).`, needsDiagram: true },
      { q: 'Describe the process of transpiration.', marks: 4, markScheme: `• Water evaporates from mesophyll cells in the leaf (1).\n• Water vapour diffuses out of the stomata (1).\n• More water is drawn up the xylem from the roots (transpiration stream) to replace it (1).\n• Water molecules stick to each other (cohesion) and to the walls (adhesion), maintaining a continuous column (1).` },
      { q: 'State four factors that affect the rate of transpiration and explain one.', marks: 4, markScheme: `• Light intensity — brighter light opens stomata more, increasing rate (1).\n• Temperature — higher temp increases evaporation (1).\n• Air movement / wind — removes water vapour from around stomata, maintaining gradient, increasing rate (1).\n• Humidity — higher humidity reduces gradient, reduces rate (1).` },
      { q: 'Describe how you would measure transpiration rate using a potometer.', marks: 5, markScheme: `• Cut a shoot under water and insert into the potometer without air bubbles (1).\n• Seal connections with petroleum jelly; ensure airtight (1).\n• Introduce an air bubble into the capillary tube by exposing it briefly (1).\n• Record the distance the bubble moves in a set time, e.g. 10 min (1).\n• Calculate rate = distance ÷ time. Change one variable (light, wind, humidity) at a time and keep others constant (1).`, needsDiagram: true },
      { q: 'State the functions of red blood cells, white blood cells, plasma and platelets.', marks: 4, markScheme: `• Red blood cells — transport oxygen (bound to haemoglobin) from lungs to tissues (1).\n• White blood cells — defend against pathogens (phagocytosis and antibody production) (1).\n• Plasma — liquid carrying blood cells, hormones, dissolved nutrients, CO₂, urea, heat (1).\n• Platelets — form clots at wounds to prevent blood loss and infection (1).` },
      { q: 'Describe three adaptations of red blood cells.', marks: 3, markScheme: `• Biconcave disc — large surface area for gas exchange (1).\n• No nucleus — more room for haemoglobin (1).\n• Contain haemoglobin — binds and carries oxygen (1).` },
      { q: 'Explain how arteries, veins and capillaries differ in wall thickness, lumen size and pressure.', marks: 6, markScheme: `• Arteries: thick muscular walls with elastic fibres (1); small lumen; carry blood at high pressure away from the heart (1).\n• Veins: thinner walls (1); larger lumen; carry blood at low pressure back to the heart; contain valves to prevent backflow (1).\n• Capillaries: walls only one cell thick for short diffusion path (1); very narrow lumen — one red blood cell wide; pressure falls to very low as blood moves through and exchanges with tissues (1).`, needsDiagram: true },
      { q: 'Calculate the heart rate (bpm) if a person has 18 beats in 15 seconds.', marks: 2, markScheme: `• Beats per second = 18 ÷ 15 = 1.2 (1).\n• Beats per minute = 1.2 × 60 = 72 bpm (1).` },
      { q: 'A person has cardiac output = stroke volume × heart rate. If stroke volume = 70 cm³ and heart rate = 75 bpm, calculate cardiac output (cm³/min).', marks: 2, markScheme: `• Cardiac output = 70 × 75 (1) = 5250 cm³/min (1).` },
      { q: 'Describe how bile aids digestion of fats.', marks: 3, markScheme: `• Bile is alkaline — neutralises stomach acid, providing optimum pH for small intestine enzymes (1).\n• Emulsifies fats into small droplets, increasing surface area (1).\n• Greater surface area means lipase can break down fats faster into fatty acids and glycerol (1).` },
      { q: 'Describe where each of these enzymes are produced and the substrate they digest: amylase, protease, lipase.', marks: 3, markScheme: `• Amylase — produced in salivary glands, pancreas, small intestine; breaks down starch to maltose (then glucose) (1).\n• Protease — stomach (pepsin), pancreas, small intestine; breaks down proteins to amino acids (1).\n• Lipase — pancreas, small intestine; breaks down lipids to fatty acids and glycerol (1).` },
      { q: 'Describe how the small intestine is adapted for absorption of digested food.', marks: 4, markScheme: `• Long and folded into villi, giving a very large surface area (1).\n• Villi have microvilli on their surface, further increasing surface area (1).\n• Walls are one cell thick — short diffusion distance (1).\n• Each villus has a good blood supply (capillary network) and a lacteal, maintaining steep gradients (1).` },
      { q: 'Describe the cause and consequence of coronary heart disease.', marks: 3, markScheme: `• Caused by build-up of fatty plaque (atheroma) in the coronary arteries, narrowing them (1).\n• Reduces blood supply (and therefore oxygen and glucose) to the heart muscle (1).\n• Muscle cells respire less efficiently — may lead to angina or heart attack if arteries are completely blocked (1).` },
      { q: 'An investigation shows 70% of patients on drug X survive compared to 50% on placebo. 20% have mild side effects. Evaluate whether drug X should be approved.', marks: 6, markScheme: `• Clear benefit: survival increased from 50% to 70%, +20 percentage points (1). Must consider sample size and statistical significance (1).\n• Side effects: 20% mild — acceptable if they are reversible and condition is serious (1).\n• Compare with any existing treatments (1).\n• Other factors: cost, availability, long-term effects not yet known (1).\n• Overall: if no better treatment exists, and benefits outweigh risks, drug X should be considered for approval but monitored in Phase 4 (1).` },
      { q: 'A student measured the rate of reaction of amylase at pH 3, 5, 7, 9 and 11 using the iodine test. Predict the shape of the graph and explain.', marks: 4, markScheme: `• Bell-shaped curve peaking at pH 7 (1).\n• Rate lowest at pH 3 and 11 (denatured) (1).\n• As pH approaches optimum, shape of active site and substrate complementary — more productive collisions (1).\n• At extreme pH, the bonds holding the active site change, denaturing the enzyme (1).`, needsDiagram: true },
      { q: 'A student has 5 cm³ of starch solution, iodine, and amylase. Describe an investigation to determine the effect of temperature on amylase activity.', marks: 6, markScheme: `• Set up water baths at different temperatures (e.g. 10, 20, 30, 40, 50, 60 °C) (1).\n• Place starch + iodine into wells of spotting tile; add amylase to the starch solution at the chosen temperature (1).\n• At regular intervals, sample a drop of mixture onto iodine (1).\n• Record time taken for iodine to stop turning blue-black (starch all digested) (1).\n• Calculate rate = 1/time (1).\n• Control variables: concentration and volume of starch, amylase, pH, time interval (1).` },
      { q: 'Describe how nicotine and carbon monoxide in tobacco smoke harm the cardiovascular system.', marks: 4, markScheme: `• Nicotine is addictive and raises heart rate and blood pressure, increasing strain on the heart (1).\n• Carbon monoxide binds irreversibly to haemoglobin, reducing oxygen-carrying capacity (1).\n• The heart must work harder to deliver the same amount of oxygen (1).\n• Long-term damage contributes to coronary heart disease, stroke, and circulation problems (1).` },
      { q: 'Describe the role of the pancreas in digestion.', marks: 3, markScheme: `• Produces digestive enzymes: amylase, protease, lipase (1).\n• Secretes them into the small intestine via the pancreatic duct (1).\n• Also produces hormones insulin and glucagon (endocrine function) to regulate blood glucose (1).` },
      { q: 'State one cause of cardiovascular disease that a person cannot change and one they can change.', marks: 2, markScheme: `• Cannot change: genetic predisposition / age / sex (1).\n• Can change: diet / smoking / exercise / alcohol intake / weight (1).` },
      { q: 'Describe briefly how an artificial heart or transplant is used to treat heart failure.', marks: 3, markScheme: `• Transplant: a donor heart replaces the damaged one — requires a matched donor and immunosuppressants for life (1).\n• Artificial heart / mechanical pump: temporarily maintains circulation while waiting for a donor (1).\n• Advantages/disadvantages: transplant offers cure but risk of rejection and donor shortage; artificial heart avoids rejection but has limited lifespan and risk of clots / infection (1).` },
      { q: 'A plant in a dry, windy field. Predict and explain the rate of transpiration compared with the same plant in a damp, still greenhouse.', marks: 3, markScheme: `• Rate is higher in the dry, windy field (1).\n• Dry air = steeper water vapour gradient between leaf and air; wind removes water vapour keeping the gradient steep (1).\n• Higher temperature also increases evaporation further (1).` },
      { q: 'Describe the functions of muscular, nervous and epithelial tissue.', marks: 3, markScheme: `• Muscular — contracts to produce movement (e.g. heart, gut, skeletal muscle) (1).\n• Nervous — transmits electrical impulses (e.g. sensory neurones) (1).\n• Epithelial — covers surfaces (e.g. gut lining) for protection, secretion and absorption (1).` },
    ]
  },

  /* ─────────────────────────────────────────────────────────── 4.3 Infection and Response */
  '4.3': {
    name: 'Infection and Response',
    questions: [
      { q: 'Define "pathogen" and state the four main types.', marks: 2, markScheme: `• A pathogen is a microorganism that causes infectious disease (1).\n• Four types: bacteria, viruses, fungi, protists (1).` },
      { q: 'Describe how bacteria cause disease.', marks: 2, markScheme: `• Bacteria may reproduce rapidly inside the body (1).\n• They produce toxins that damage cells/tissues, causing symptoms (1).` },
      { q: 'Describe how viruses cause disease.', marks: 3, markScheme: `• Viruses enter host cells and use the cell\'s machinery to replicate (1).\n• Many viruses are released, bursting the cell (cell lysis) (1).\n• Damaged cells cause symptoms of disease (1).` },
      { q: 'State three ways in which infections can be transmitted, giving an example for each.', marks: 3, markScheme: `• Direct contact — HIV (through bodily fluids) (1).\n• Airborne droplets — measles, flu (coughs/sneezes) (1).\n• Contaminated food or water — salmonella, cholera (1). (Also accept: vector — malaria via mosquitoes.)` },
      { q: 'State the symptoms of measles and how it is spread.', marks: 3, markScheme: `• Symptoms: high fever, red skin rash (1).\n• Complications can be serious, including death (1).\n• Spread by droplet infection (coughs, sneezes) (1). Prevented by vaccination.` },
      { q: 'Describe how HIV is transmitted and how it progresses to AIDS.', marks: 4, markScheme: `• HIV is spread by sexual contact, exchange of body fluids such as blood, or mother-to-child (breast feeding) (1).\n• Initially causes a flu-like illness for a few weeks (1).\n• The virus infects and destroys helper T-lymphocytes, weakening the immune system over years (1).\n• Late-stage HIV/AIDS — immune system cannot fight infections or cancers, which can be fatal (1). Controlled with antiretroviral drugs.` },
      { q: 'Describe the effects of TMV on tobacco plants and how it is transmitted.', marks: 3, markScheme: `• Causes a distinctive mosaic (pale/yellow) pattern on leaves (1).\n• Reduces chlorophyll, so less photosynthesis and poor growth / low yield (1).\n• Spreads by direct contact between plants and through insect vectors (e.g. aphids) (1).` },
      { q: 'Describe the symptoms, cause and treatment of salmonella food poisoning.', marks: 4, markScheme: `• Symptoms: fever, abdominal cramps, vomiting, diarrhoea (1).\n• Caused by Salmonella bacteria and their toxins (1).\n• Spread in undercooked or contaminated food (1).\n• Prevented by vaccinating poultry, good hygiene and cooking food thoroughly (1).` },
      { q: 'Describe how malaria is transmitted and how it can be prevented.', marks: 4, markScheme: `• Caused by protist (Plasmodium) (1).\n• Transmitted by mosquitoes (vectors) feeding on blood — female Anopheles (1).\n• Parasite multiplies in liver and red blood cells, causing recurrent fever (1).\n• Prevention: insecticides, mosquito nets, removing standing water, antimalarial drugs, new vaccines (1).` },
      { q: 'State three ways the human body acts as a barrier to pathogens.', marks: 3, markScheme: `• Skin is a physical barrier and produces antimicrobial secretions (1).\n• Mucus lining of nose/trachea traps pathogens; cilia sweep them away (1).\n• Stomach acid kills most swallowed pathogens (1). (Also accept: tears contain lysozyme.)` },
      { q: 'Describe two roles of white blood cells in defence.', marks: 3, markScheme: `• Phagocytosis — engulf and digest pathogens (1).\n• Production of antibodies — specific to antigens on the pathogen (1), causing agglutination or marking pathogens for destruction.\n• Production of antitoxins — neutralise toxins (1 for a third point).` },
      { q: 'Explain how a vaccine works.', marks: 4, markScheme: `• Contains a small amount of dead/inactive pathogen or antigen (1).\n• White blood cells produce antibodies against the antigen (1).\n• Memory lymphocytes remain (1).\n• On later exposure, secondary response is rapid and large, destroying pathogen before symptoms develop — person is immune (1).` },
      { q: 'Explain what is meant by herd immunity.', marks: 3, markScheme: `• If a large proportion of a population is vaccinated, the pathogen cannot spread easily (1).\n• Those who cannot be vaccinated (e.g. babies, immunocompromised) are indirectly protected (1).\n• Reduces incidence and may eliminate disease from a population (1).` },
      { q: 'State why antibiotics are not effective against viruses.', marks: 2, markScheme: `• Antibiotics target specific bacterial structures or processes (e.g. cell walls, ribosomes) (1).\n• Viruses have no bacterial targets and live inside host cells — damaging the virus would also damage the host cell (1).` },
      { q: 'Explain how the overuse of antibiotics leads to the emergence of resistant bacteria.', marks: 5, markScheme: `• Random mutations create resistant bacteria (1).\n• Non-resistant bacteria are killed when antibiotic is used (1).\n• Resistant bacteria survive and reproduce, passing on resistance genes (1).\n• Over generations, resistant strains dominate — natural selection in action (1).\n• New resistant strains spread in hospitals and community, causing hard-to-treat infections (e.g. MRSA) (1).` },
      { q: 'Describe the three main stages of drug testing.', marks: 3, markScheme: `• Preclinical: tested on cells, tissues and live animals for safety and efficacy (1).\n• Clinical (Phase 1): small groups of healthy volunteers at low dose — check safety and side effects (1).\n• Clinical (Phase 2 & 3): larger groups of patients — check efficacy and optimal dose; double-blind placebo trials (1).` },
      { q: 'Explain what "placebo", "double-blind" and "randomised" mean in a clinical trial.', marks: 3, markScheme: `• Placebo — dummy treatment with no active drug to control for psychological effects (1).\n• Double-blind — neither doctor nor patient knows who is receiving drug vs placebo (1).\n• Randomised — patients are randomly assigned to groups to avoid bias (1).` },
      { q: 'Describe how monoclonal antibodies are produced.', marks: 5, markScheme: `• Inject mouse with antigen; lymphocytes in the mouse produce antibodies against the antigen (1).\n• Lymphocytes are collected from the mouse spleen (1).\n• Fused with fast-dividing tumour (myeloma) cells to form hybridoma cells (1).\n• Hybridomas are cloned; selected colonies produce large amounts of identical antibody (1).\n• Antibodies are collected and purified for use (1).` },
      { q: 'State three uses of monoclonal antibodies.', marks: 3, markScheme: `• Pregnancy testing — detect hCG in urine (1).\n• Diagnosing and treating cancer — antibodies bind to cancer cell antigens, carrying drugs or marking for destruction (1).\n• Research / detecting particular molecules in a cell (1). (Also accept: identifying pathogens in blood/tissue tests.)` },
      { q: 'Evaluate the use of monoclonal antibodies in treatment.', marks: 6, markScheme: `• Advantages: highly specific to cancer cells, fewer side effects than chemotherapy (1); can deliver drugs directly (1); diagnostic accuracy (1).\n• Disadvantages: produced in mice — ethical/allergic reaction concerns (1); expensive to produce (1); some side effects more severe than expected (1).\n• Conclusion: very promising for cancer and autoimmune diseases; ongoing improvements (humanised antibodies) reduce drawbacks.` },
      { q: 'State four visible signs that a plant may be diseased.', marks: 4, markScheme: `• Stunted growth (1).\n• Spots on leaves / discolouration (1).\n• Areas of decay (rot) / abnormal growths (1).\n• Malformed stems/leaves; presence of visible pests (1).` },
      { q: 'Describe how a plant\'s mineral deficiency can be identified: nitrate vs magnesium.', marks: 2, markScheme: `• Nitrate deficiency — stunted growth because amino acids (for proteins) cannot be made (1).\n• Magnesium deficiency — yellow leaves (chlorosis) because chlorophyll cannot be made (1).` },
      { q: 'Describe two physical, two chemical and two mechanical plant defences.', marks: 6, markScheme: `• Physical: cellulose cell walls (1); waxy cuticle and/or bark / layers of dead cells on stems (1).\n• Chemical: antibacterial secretions (e.g. in mint, witch hazel) (1); poisons to deter herbivores (e.g. caffeine, nicotine) (1).\n• Mechanical: thorns/hairs (1); leaves which droop or curl on contact / mimicry (1).` },
      { q: 'Explain why it is important to complete the full course of prescribed antibiotics.', marks: 3, markScheme: `• Stopping early leaves surviving bacteria that have partial resistance (1).\n• These can multiply and increase the frequency of resistance in the population (1).\n• Reduces the chance of the person\'s infection coming back worse and lowers risk of resistant strains developing (1).` },
      { q: 'Describe why the development of new antibiotics has not kept pace with growing resistance.', marks: 3, markScheme: `• Developing a new antibiotic is slow and expensive (1).\n• Pharmaceutical companies make more money from chronic-disease drugs than from antibiotics (1).\n• New antibiotics are held in reserve to preserve effectiveness, limiting profit (1).` },
      { q: 'A student cultures bacteria on agar with 3 antibiotic discs. Zone diameters are A=30 mm, B=12 mm, C=0 mm. Calculate the area (π=3.14) of the clear zone for A and rank the antibiotics.', marks: 3, markScheme: `• Area of A = π × r² = 3.14 × 15² = 706.5 mm² (1).\n• Rank: A (most effective — largest zone), B, C (no effect — bacteria resistant) (1).\n• Justification: larger clear zone = more bacteria killed (1).` },
      { q: 'A lawn of bacteria is grown in a petri dish. Explain the importance of aseptic technique.', marks: 4, markScheme: `• Prevents contamination from airborne microorganisms that would compete with or confuse the results (1).\n• Sterilise equipment before and after use (flamed loop, autoclave petri dishes) (1).\n• Work near a Bunsen flame to produce an updraft (1).\n• Tape petri dish lid to reduce contamination but not seal airtight; incubate at <25 °C in schools to reduce risk of pathogens (1).` },
      { q: 'Explain why TB patients now often require long courses of multiple drugs.', marks: 3, markScheme: `• TB bacteria have developed resistance to many common antibiotics (1).\n• Multiple drugs with different modes of action reduce chance of mutations conferring resistance to all of them (1).\n• Long courses ensure all bacteria (including slower-growing ones) are killed, preventing relapse (1).` },
      { q: 'A child who has never had chicken pox now has chicken pox. 10 years later, they do not catch it again despite exposure. Explain.', marks: 4, markScheme: `• First infection triggered an immune response; white blood cells produced antibodies against chicken pox virus antigens (1).\n• Memory B-lymphocytes remain (1).\n• On second exposure, memory cells rapidly divide and produce large amounts of antibody quickly (1).\n• Pathogen is destroyed before symptoms appear — the child has natural immunity (1).` },
      { q: 'Suggest why newer drugs are more expensive than older medications.', marks: 3, markScheme: `• Development of a new drug involves 10–15 years of research and testing (1).\n• Pre-clinical and clinical trials cost hundreds of millions of pounds (1).\n• Patents allow the company to recover costs; after the patent expires generic alternatives become much cheaper (1).` },
      { q: 'Describe the origin of three important medicines from plants or microorganisms.', marks: 3, markScheme: `• Aspirin (painkiller) — originally from willow bark (1).\n• Digitalis (heart drug) — from foxgloves (1).\n• Penicillin (antibiotic) — from the mould Penicillium (discovered by Alexander Fleming) (1).` },
      { q: 'Describe how the flu vaccine is different each year.', marks: 3, markScheme: `• Flu viruses mutate rapidly (antigenic drift) (1).\n• WHO monitors strains circulating and recommends a new vaccine composition each year (1).\n• New vaccine is grown/produced and administered to at-risk groups before flu season (1).` },
      { q: 'Explain why a drug may still be withdrawn even after passing all trials (e.g. thalidomide).', marks: 4, markScheme: `• Trials cannot anticipate every side effect, especially rare or long-term effects (1).\n• Specific populations may not have been tested (e.g. pregnant women) (1).\n• If serious side effects emerge once in widespread use (e.g. birth defects), regulators withdraw the drug (1).\n• Example: thalidomide caused severe limb malformations in babies, leading to tighter drug testing requirements (1).` },
      { q: 'Suggest why antibiotic resistance is worse in hospitals than in the community.', marks: 3, markScheme: `• Patients in hospital often have weaker immune systems (1).\n• Antibiotics are used frequently, creating strong selection pressure (1).\n• Resistant bacteria (e.g. MRSA) spread between patients via staff, equipment, or surfaces (1).` },
      { q: 'Describe the body\'s response to a cut on the skin.', marks: 4, markScheme: `• Platelets gather at the wound and release clotting factors (1).\n• A fibrin mesh forms a clot, blocking the wound (1).\n• White blood cells arrive to ingest any pathogens that entered (1).\n• New skin cells divide (mitosis) to repair the tissue (1).` },
      { q: 'Describe how the structure of a monoclonal antibody allows it to be used for targeted cancer treatment.', marks: 4, markScheme: `• The antibody has a specific variable region that binds to a specific antigen on cancer cells (1).\n• An anti-cancer drug or radioactive substance can be attached to the antibody (1).\n• Antibody-drug conjugate binds specifically to cancer cells, delivering the drug (1).\n• Healthy cells are largely spared — fewer side effects than traditional chemotherapy (1).` },
      { q: 'A student claims: "All microorganisms cause disease." Evaluate this statement.', marks: 4, markScheme: `• Statement is incorrect (1).\n• Many microorganisms are harmless or beneficial (1).\n• Examples: gut bacteria aid digestion; decomposers recycle nutrients; bacteria are used to make yoghurt, cheese, insulin (1).\n• Only a small proportion are pathogens that cause disease (1).` },
      { q: 'Explain why MMR vaccine includes three weakened viruses in one jab.', marks: 3, markScheme: `• Vaccinates against measles, mumps, rubella in a single dose (1).\n• Reduces number of injections and clinic visits, increasing uptake (1).\n• Increases herd immunity — once uptake exceeds ~95%, these diseases can be almost eliminated (1).` },
      { q: 'A patient has a severe bacterial infection and is given an antibiotic. After 7 days they feel well but still have 2 days of antibiotics left. Advise the patient.', marks: 3, markScheme: `• Finish the full course (1).\n• Otherwise residual bacteria with some resistance survive and could cause infection to return (1).\n• Resistant bacteria may be passed to other people — a public health risk (1).` },
      { q: 'Describe and explain the immune response after first exposure vs second exposure to the same pathogen.', marks: 4, markScheme: `• First exposure (primary response): slow — takes days to weeks to build up antibody levels; person usually becomes ill (1).\n• Memory lymphocytes are produced and remain in the blood (1).\n• Second exposure (secondary response): memory cells rapidly divide and produce large amounts of antibody within days (1).\n• Pathogen is destroyed before symptoms develop — the person is immune (1).`, needsDiagram: true },
    ]
  },

  /* ─────────────────────────────────────────────────────────── 4.4 Bioenergetics */
  '4.4': {
    name: 'Bioenergetics',
    questions: [
      { q: 'Write the balanced symbol equation for photosynthesis.', marks: 2, markScheme: `• 6CO₂ + 6H₂O → C₆H₁₂O₆ + 6O₂ (2). (1 for correct formulas; 1 for balancing.)` },
      { q: 'State the word equation for aerobic respiration.', marks: 1, markScheme: `• Glucose + oxygen → carbon dioxide + water (+ energy released) (1).` },
      { q: 'State the word equation for anaerobic respiration in muscle cells and in yeast.', marks: 2, markScheme: `• Muscle: glucose → lactic acid (1).\n• Yeast: glucose → ethanol + carbon dioxide (1).` },
      { q: 'State the site of photosynthesis and the site of aerobic respiration in a plant cell.', marks: 2, markScheme: `• Photosynthesis — chloroplasts (1).\n• Aerobic respiration — mitochondria (1).` },
      { q: 'Explain why photosynthesis is described as endothermic.', marks: 2, markScheme: `• Energy is transferred from the environment (light) into the reaction (1).\n• Overall reaction takes in more energy than it releases (1).` },
      { q: 'State three uses of glucose produced by photosynthesis in a plant.', marks: 3, markScheme: `• Respiration for energy (1).\n• Stored as insoluble starch (1).\n• Used to make cellulose (cell walls); fats/oils; amino acids (with nitrates for proteins) (1).` },
      { q: 'Name three factors that may limit the rate of photosynthesis.', marks: 3, markScheme: `• Light intensity (1).\n• Carbon dioxide concentration (1).\n• Temperature (1). (Also accept: amount of chlorophyll / water, but rarely water.)` },
      { q: 'Describe the effect of increasing light intensity on the rate of photosynthesis when CO₂ and temperature are not limiting.', marks: 3, markScheme: `• Rate increases in proportion to light intensity initially (1).\n• Rate continues to increase but at a slower rate as another factor begins to limit (1).\n• Eventually rate plateaus — increasing light no longer increases rate (other factor is limiting) (1).`, needsDiagram: true },
      { q: 'A lamp produces 100 bubbles/min at 10 cm from pondweed. Predict the rate at 20 cm assuming light is the only limiting factor. Show working.', marks: 2, markScheme: `• Light intensity ∝ 1/d²; doubling distance reduces intensity by factor 4 (1).\n• Predicted rate = 100 ÷ 4 = 25 bubbles/min (1).` },
      { q: 'Explain why a commercial greenhouse farmer might add CO₂ to the air.', marks: 3, markScheme: `• CO₂ is often the limiting factor in greenhouses (1).\n• Adding CO₂ increases the rate of photosynthesis (1).\n• Greater glucose production leads to more growth and higher crop yield, provided cost of adding CO₂ is less than extra profit (1).` },
      { q: 'Explain the effect of temperature on the rate of photosynthesis.', marks: 4, markScheme: `• Up to the optimum, higher temperature provides more kinetic energy to enzymes controlling photosynthesis — rate increases (1).\n• At the optimum temperature, rate is maximum (1).\n• Above the optimum, enzymes denature (1).\n• Rate decreases sharply because active site changes shape and substrate no longer fits (1).` },
      { q: 'Explain why glucose is usually converted to starch in plant storage organs rather than stored as glucose.', marks: 3, markScheme: `• Glucose is soluble — would affect water potential and draw water in by osmosis (1).\n• Starch is insoluble — no effect on water potential (1).\n• Starch is also a more compact store (many glucose units) (1).` },
      { q: 'Describe how the body responds to exercise in terms of heart rate, breathing rate and breathing depth.', marks: 3, markScheme: `• Heart rate increases — pumps more oxygenated blood and removes more CO₂ per minute (1).\n• Breathing rate increases (1).\n• Breath depth (tidal volume) increases — more O₂ taken in and CO₂ exhaled per breath (1).` },
      { q: 'Define "oxygen debt".', marks: 2, markScheme: `• The amount of extra oxygen needed after exercise (1) to oxidise the accumulated lactic acid to carbon dioxide and water (1).` },
      { q: 'Explain what happens to lactic acid after exercise.', marks: 3, markScheme: `• Blood carries lactic acid to the liver (1).\n• Lactic acid is converted back to glucose, using oxygen (1).\n• This is why breathing and heart rate remain high after exercise stops — to repay the oxygen debt (1).` },
      { q: 'State three uses of the energy released by respiration in the body.', marks: 3, markScheme: `• Muscle contraction (movement) (1).\n• Building larger molecules (proteins) from smaller ones (1).\n• Maintaining body temperature in mammals and birds (1). (Also accept: active transport, nerve impulse transmission.)` },
      { q: 'Compare the energy released by aerobic and anaerobic respiration of one glucose molecule.', marks: 2, markScheme: `• Aerobic releases much more energy per molecule than anaerobic (1).\n• Because aerobic oxidises glucose fully to CO₂ and water, while anaerobic leaves much energy locked in the product (lactic acid or ethanol) (1).` },
      { q: 'Name the process in yeast that is used in brewing and baking, and give the equation.', marks: 3, markScheme: `• Fermentation — glucose → ethanol + carbon dioxide (1).\n• In brewing: ethanol is the desired product (alcohol) (1).\n• In baking: CO₂ makes the dough rise; ethanol is driven off during baking (1).` },
      { q: 'Define "metabolism".', marks: 2, markScheme: `• Metabolism is the sum of all the chemical reactions in a cell or the body (1).\n• Includes building and breaking down molecules, and energy transfer (1).` },
      { q: 'Describe how a plant uses glucose and nitrate ions to make amino acids.', marks: 3, markScheme: `• Plants absorb nitrate ions (NO₃⁻) from soil through root hair cells (1).\n• In leaves, glucose and nitrate ions combine in chemical reactions (1).\n• The resulting amino acids are joined in ribosomes to form proteins (1).` },
      { q: 'In a photosynthesis experiment, a student records rate of O₂ produced per minute at three temperatures with constant light and CO₂. Predict and explain the effect of raising temperature from 15 °C to 25 °C.', marks: 3, markScheme: `• Rate increases (1).\n• Because enzymes involved in photosynthesis have more kinetic energy and achieve more successful collisions with substrate (1).\n• Higher temperature also increases diffusion rate of CO₂ into the leaf (1).` },
      { q: 'Evaluate the economic decision to raise CO₂ levels in a greenhouse.', marks: 4, markScheme: `• Adding CO₂ increases photosynthesis → more biomass / crop yield → more profit (1).\n• Cost of CO₂ supply, equipment, maintenance must be considered (1).\n• Only worthwhile if the extra yield raises income more than the extra costs (1).\n• Also consider alternative investments (e.g. heating, lighting) that might give better returns depending on conditions (1).` },
      { q: 'Describe an investigation to measure the rate of photosynthesis in pondweed.', marks: 6, markScheme: `• Place a piece of pondweed in a beaker of sodium hydrogencarbonate solution (CO₂ source) (1).\n• Keep water bath at a set temperature (1).\n• Place a lamp at varying distances (e.g. 10, 20, 30, 40 cm) (1).\n• Count bubbles produced per minute or collect O₂ in a gas syringe (1).\n• Repeat for each distance and find mean (1).\n• Plot graph of rate vs 1/d² and describe the pattern (1).`, needsDiagram: true },
      { q: 'A plant has 10 cm³ O₂ produced in 5 min when CO₂ is low. Raising CO₂ gives 40 cm³ in 5 min. Calculate both rates and explain.', marks: 3, markScheme: `• Low CO₂: rate = 10/5 = 2 cm³/min (1).\n• High CO₂: rate = 40/5 = 8 cm³/min (1).\n• Rate is 4× higher because CO₂ was the limiting factor at low concentration — adding CO₂ increases rate until another factor becomes limiting (1).` },
      { q: 'Compare glycogen (animals) and starch (plants) as energy stores.', marks: 3, markScheme: `• Both are polymers of glucose and insoluble (1).\n• Glycogen is more highly branched — faster glucose release for animal movement (1).\n• Starch has less branching; plants do not need such rapid release (1).` },
      { q: 'Explain why a runner\'s breathing rate remains elevated for several minutes after a sprint.', marks: 3, markScheme: `• Anaerobic respiration during sprint produced lactic acid (1).\n• Oxygen debt must be repaid: extra O₂ needed to oxidise lactic acid (1).\n• Breathing and heart rate stay high until lactate is cleared and normal O₂ / glucose supplies restored (1).` },
      { q: 'Describe the effect of altitude on breathing rate.', marks: 2, markScheme: `• At high altitude, air has lower O₂ concentration (1).\n• Breathing rate and depth increase to take in enough O₂ / maintain O₂ delivery to cells (1).` },
      { q: 'Explain why plants photosynthesise more during the day, but respire continuously.', marks: 3, markScheme: `• Photosynthesis requires light, so only occurs in daylight (or under artificial light) (1).\n• Respiration releases energy from glucose, needed at all times (1).\n• At night, there is net O₂ uptake and CO₂ release; during the day, photosynthesis exceeds respiration and the plant has net O₂ release (1).` },
      { q: 'A plant shows no net gas exchange. Explain what this means and when it occurs.', marks: 3, markScheme: `• Rate of photosynthesis = rate of respiration (1).\n• O₂ produced by photosynthesis is exactly used by respiration; CO₂ produced by respiration is exactly used by photosynthesis (1).\n• Occurs at compensation point — at a particular low light intensity early morning/evening (1).` },
      { q: 'Explain why respiration is essential even for plants.', marks: 2, markScheme: `• Plants need energy for growth, active transport (e.g. mineral uptake), and protein synthesis (1).\n• They respire continuously; photosynthesis only produces glucose, which must be respired for energy (1).` },
      { q: 'Describe the effect on a plant of being kept in darkness for a week.', marks: 3, markScheme: `• No photosynthesis, so no new glucose is produced (1).\n• Plant uses stored starch (converted back to glucose) for respiration (1).\n• Eventually reserves exhausted — growth stops, leaves may yellow, plant dies if no further light (1).` },
      { q: 'A greenhouse farmer grows tomatoes and uses paraffin heaters. Explain two benefits of paraffin heaters.', marks: 2, markScheme: `• Raises temperature — increases rate of photosynthesis (up to optimum) and prevents frost damage (1).\n• Releases CO₂ from combustion, raising CO₂ concentration (1).` },
      { q: 'A competitive runner prepares for a race. Explain why they warm up before and cool down after.', marks: 4, markScheme: `• Warm up: increases blood flow to muscles; muscle temperature rises, enzymes work faster (1); reduces risk of injury (1).\n• Cool down: continues elevated breathing and blood flow to clear lactic acid (1); prevents lactic acid build-up and reduces muscle soreness/stiffness afterwards (1).` },
      { q: 'Describe and explain the shape of a graph showing rate of respiration against time during a 400 m race.', marks: 4, markScheme: `• Rate rises steeply as exercise begins — oxygen demand increases (1).\n• Rate plateaus at maximum during the race (1).\n• Anaerobic respiration supplements aerobic when O₂ demand exceeds supply (1).\n• After race ends, aerobic rate stays high to repay oxygen debt, then gradually returns to baseline (1).`, needsDiagram: true },
      { q: 'Calculate: a leaf area of 20 cm² produces 0.8 cm³ O₂ in 4 minutes. Calculate rate per cm² per min.', marks: 2, markScheme: `• Rate per min = 0.8 / 4 = 0.2 cm³/min (1).\n• Rate per cm² per min = 0.2 / 20 = 0.01 cm³/cm²/min (1).` },
      { q: 'Explain why the rate of transpiration and rate of photosynthesis are closely linked.', marks: 3, markScheme: `• Stomata must open to allow CO₂ in for photosynthesis (1).\n• Water vapour is lost through the same stomata — driving transpiration (1).\n• When the plant closes stomata to conserve water, photosynthesis slows — a trade-off (1).` },
      { q: 'Evaluate the use of fish farming, linking to trophic levels and efficiency.', marks: 4, markScheme: `• Fish farms provide a sustainable protein source and reduce overfishing wild stocks (1).\n• Fish are fed on manufactured feed — energy lost at each trophic level (1).\n• Concerns: pollution from waste, disease spread, ecological impact (1).\n• Vegetarian fish (e.g. tilapia) are more efficient than carnivorous fish (e.g. salmon); aquaculture design must minimise impact (1).` },
      { q: 'A student measures the rate of germination of seeds at different temperatures. Explain why germination rate peaks at ~25 °C.', marks: 3, markScheme: `• Germination is controlled by enzymes (1).\n• Rate increases with temperature up to an optimum (1).\n• Above the optimum, enzymes denature and rate falls sharply; below the optimum, kinetic energy is too low (1).` },
      { q: 'Describe the route of CO₂ from a respiring muscle cell to the atmosphere.', marks: 4, markScheme: `• CO₂ diffuses out of the cell into blood plasma (1).\n• Transported via the veins to the right side of the heart → pulmonary artery → lungs (1).\n• CO₂ diffuses from blood into the alveoli (1).\n• Exhaled out via the bronchioles, bronchi, trachea, mouth/nose (1).` },
      { q: '"Plants only photosynthesise, they do not respire." Evaluate this statement.', marks: 3, markScheme: `• The statement is incorrect (1).\n• Plants respire continuously using glucose (produced by photosynthesis) to release energy for growth, active transport, and other processes (1).\n• Respiration occurs in mitochondria of all living plant cells, day and night (1).` },
    ]
  },

  /* ─────────────────────────────────────────────────────────── 4.5 Homeostasis and Response */
  '4.5': {
    name: 'Homeostasis and Response',
    questions: [
      { q: 'Define "homeostasis".', marks: 2, markScheme: `• The regulation of the internal conditions of a cell or organism (1)\n• To maintain optimum conditions for function, in response to internal and external change (1).` },
      { q: 'State three variables that are regulated by homeostasis in humans.', marks: 3, markScheme: `• Body temperature (1).\n• Blood glucose concentration (1).\n• Water/ion concentration (osmotic balance) (1).` },
      { q: 'Describe the components of a control system.', marks: 3, markScheme: `• Receptors that detect change in the environment (stimulus) (1).\n• Coordination centre (brain, spinal cord or pancreas) that processes the information (1).\n• Effectors (muscles or glands) that bring about the response to restore optimum (1).` },
      { q: 'Describe the order of a reflex arc with an example.', marks: 3, markScheme: `• Stimulus → receptor → sensory neurone → relay neurone (in CNS) → motor neurone → effector → response (1 for correct order; 1 more for full detail).\n• Example: touching a hot object — pain receptor in skin → sensory neurone → spinal cord → motor neurone → biceps muscle contracts → hand pulls away (1).`, needsDiagram: true },
      { q: 'Explain why reflex actions are fast.', marks: 3, markScheme: `• Involve only two synapses (instead of involving the brain for conscious thought) (1).\n• Nerve impulses travel rapidly along myelinated neurones (1).\n• The response is automatic — no conscious decision needed — this protects the body from harm (1).` },
      { q: 'Name three parts of the brain and state a function of each.', marks: 3, markScheme: `• Cerebrum / cerebral cortex — higher functions: thought, memory, consciousness, voluntary movement (1).\n• Cerebellum — coordination of muscle movement and balance (1).\n• Medulla — controls unconscious activities e.g. heart rate and breathing rate (1).` },
      { q: 'Describe the structure of the eye.', marks: 5, markScheme: `• Cornea — refracts light (1).\n• Iris — controls amount of light entering pupil (1).\n• Lens — focuses light on the retina (1).\n• Retina — contains rods and cones, detects light and colour (1).\n• Optic nerve — carries impulses to the brain (1).`, needsDiagram: true },
      { q: 'Describe how the eye focuses on a distant vs a near object (accommodation).', marks: 4, markScheme: `• Distant object: ciliary muscles relax, suspensory ligaments tight, lens pulled thin (less refraction) (1).\n• Near object: ciliary muscles contract, suspensory ligaments slacken, lens becomes thicker/more rounded (more refraction) (1).\n• The lens changes shape to focus light on the retina (1).\n• Known as accommodation (1).` },
      { q: 'Explain the causes and correction of long-sightedness and short-sightedness.', marks: 4, markScheme: `• Long-sightedness (hyperopia): near objects blurred — light focused behind retina (eyeball too short or lens too thin) — corrected with convex (converging) lens (1) (1).\n• Short-sightedness (myopia): far objects blurred — light focused in front of retina (eyeball too long or lens too thick) — corrected with concave (diverging) lens (1) (1).` },
      { q: 'Describe how the body responds to a rise in core temperature.', marks: 4, markScheme: `• Thermoreceptors in skin/hypothalamus detect rise (1).\n• Sweat glands produce sweat; evaporation removes heat (1).\n• Arterioles near skin dilate (vasodilation) — more heat lost by radiation (1).\n• Body temperature falls back to normal; sweating and dilation reduce — negative feedback (1).` },
      { q: 'Describe how the body responds to a fall in core temperature.', marks: 4, markScheme: `• Thermoreceptors detect fall (1).\n• Shivering — rapid muscle contractions generate heat from increased respiration (1).\n• Arterioles near skin constrict (vasoconstriction) — less blood flow to surface, less heat loss (1).\n• Erector muscles contract (hair "standing up") trapping air as insulation; less sweat — negative feedback (1).` },
      { q: 'State the main hormone that controls blood glucose when it is high, and when it is low.', marks: 2, markScheme: `• High blood glucose — insulin (from pancreas) (1).\n• Low blood glucose — glucagon (from pancreas) (1).` },
      { q: 'Describe how insulin lowers blood glucose.', marks: 3, markScheme: `• Insulin is released from the pancreas when blood glucose rises (1).\n• It causes liver and muscle cells to take up glucose from the blood (1).\n• Glucose is stored as glycogen; blood glucose returns to normal (1).` },
      { q: 'Describe how glucagon raises blood glucose.', marks: 3, markScheme: `• When blood glucose is low, the pancreas releases glucagon (1).\n• Glucagon stimulates the liver to break down glycogen to glucose (1).\n• Glucose is released into the blood, raising blood glucose back to normal (1).` },
      { q: 'Compare Type 1 and Type 2 diabetes.', marks: 4, markScheme: `• Type 1: pancreas produces too little insulin (often autoimmune destruction of β-cells); usually diagnosed in childhood (1). Treated with insulin injections and careful diet/monitoring (1).\n• Type 2: body cells no longer respond properly to insulin (insulin resistance); linked to obesity and inactivity, usually adult onset (1). Treated with diet, exercise, sometimes drugs and eventually insulin (1).` },
      { q: 'Explain two risk factors for Type 2 diabetes.', marks: 2, markScheme: `• Obesity — excess body fat reduces sensitivity of cells to insulin (1).\n• Sedentary lifestyle — low activity contributes to obesity and insulin resistance (1). (Also accept: genetics, age, ethnicity, diet high in sugars.)` },
      { q: 'Describe the role of the kidneys in homeostasis.', marks: 3, markScheme: `• Filter the blood removing waste (urea, excess ions, excess water) (1).\n• Reabsorb useful substances (glucose, essential ions, water as needed) (1).\n• Excrete urine (waste products) to maintain constant internal conditions (1).` },
      { q: 'Describe how urea is formed and excreted.', marks: 3, markScheme: `• Excess amino acids are broken down in the liver — deamination (1) — producing ammonia.\n• Ammonia (toxic) is converted to urea (1).\n• Urea is filtered from the blood by the kidneys and excreted in urine (1).` },
      { q: 'Explain how ADH regulates the water content of the body.', marks: 4, markScheme: `• When blood is too concentrated (dehydration), the hypothalamus detects this via osmoreceptors (1).\n• The pituitary releases ADH (antidiuretic hormone) (1).\n• ADH makes the kidney tubules (collecting duct) more permeable to water (1).\n• More water reabsorbed back into the blood — urine becomes more concentrated; less urine produced (1).` },
      { q: 'Explain dialysis as treatment for kidney failure.', marks: 4, markScheme: `• Patient\'s blood flows through a dialyser alongside dialysis fluid separated by a partially permeable membrane (1).\n• Dialysis fluid contains normal concentrations of glucose and ions, and no urea (1).\n• Urea and excess ions diffuse from blood to dialysis fluid; glucose and useful ions remain (1).\n• Blood is returned to the patient; must be repeated several times a week — dietary restrictions between sessions (1).` },
      { q: 'Evaluate kidney transplants vs dialysis.', marks: 6, markScheme: `• Transplant: long-term solution, patient lives more normally, cheaper in the long run (1). Disadvantages: risk of rejection, need for immunosuppressants, shortage of donors, surgical risks (1).\n• Dialysis: available, no major surgery (1). Disadvantages: 3+ sessions/week, restrictive diet, tied to machine, infection risks, more expensive over years (1).\n• Transplant is usually preferred if a suitable donor is available and the patient is healthy enough for surgery (1).\n• Dialysis used while waiting for transplant or if transplant not possible (1).` },
      { q: 'Describe the function of FSH in the menstrual cycle.', marks: 2, markScheme: `• FSH (follicle-stimulating hormone) is released from the pituitary (1).\n• It causes an egg to mature in an ovary and stimulates oestrogen production (1).` },
      { q: 'Describe the role of LH.', marks: 2, markScheme: `• LH (luteinising hormone) from the pituitary causes ovulation (1).\n• Release of the mature egg from the ovary at around day 14 (1).` },
      { q: 'Describe the roles of oestrogen and progesterone in the menstrual cycle.', marks: 3, markScheme: `• Oestrogen (from ovary) causes the uterus lining to thicken; inhibits FSH and at a peak stimulates LH release (1).\n• Progesterone (from corpus luteum) maintains the uterus lining (1).\n• If fertilisation does not occur, progesterone levels fall and the lining is shed (menstruation) (1).` },
      { q: 'Describe how the contraceptive pill prevents pregnancy.', marks: 3, markScheme: `• Contains oestrogen and progesterone (or progesterone only) (1).\n• Inhibits FSH, preventing egg maturation (1).\n• Also thickens cervical mucus (making sperm entry harder) and thins uterus lining (preventing implantation) (1).` },
      { q: 'Describe the stages of IVF.', marks: 5, markScheme: `• Mother given FSH and LH to stimulate maturation of multiple eggs (1).\n• Eggs are collected (1).\n• Eggs are fertilised with sperm in the lab (1).\n• Fertilised embryos develop to a few-cell stage (1).\n• One or two embryos are implanted into the mother\'s uterus (1).` },
      { q: 'Evaluate IVF treatment.', marks: 4, markScheme: `• Gives infertile couples a chance of a biological child (1).\n• Low success rate (~30%); emotionally and physically demanding; expensive (1).\n• Hormone treatment can have side effects (1).\n• Multiple births (twins/triplets) more likely — risks to mother and babies; ethical issues about unused embryos (1).` },
      { q: 'Explain how adrenaline prepares the body for "fight or flight".', marks: 4, markScheme: `• Released from adrenal glands when stressed or frightened (1).\n• Increases heart rate and blood pressure — more oxygen and glucose to muscles (1).\n• Dilates pupils (better vision); dilates airways (more O₂); redirects blood from gut to muscles (1).\n• Stimulates glycogen → glucose conversion in liver — more energy available for respiration (1).` },
      { q: 'Explain how thyroxine is regulated by negative feedback.', marks: 4, markScheme: `• Thyroxine from the thyroid raises metabolic rate (1).\n• TSH from the pituitary stimulates thyroxine release (1).\n• Rising thyroxine inhibits TSH release from the pituitary (1).\n• Falling thyroxine removes inhibition so more TSH is released — keeps thyroxine at a stable level (1).` },
      { q: 'Describe an investigation to show positive phototropism in a cress seedling.', marks: 5, markScheme: `• Grow cress seedlings in pots under different light conditions (1).\n• One pot: uniform light from above (control) (1).\n• Other pot: light only from one side (1).\n• Observe and measure how much the shoots bend (1).\n• Result: seedlings under unidirectional light bend towards light (positive phototropism) because auxin redistributes to the shaded side, causing elongation on that side (1).`, needsDiagram: true },
      { q: 'Describe how auxins cause shoots to grow towards light.', marks: 3, markScheme: `• Auxin produced at shoot tip (1).\n• When light is from one side, auxin moves to the shaded side (1).\n• Higher auxin causes more elongation of shaded-side cells; shoot bends towards light (1).` },
      { q: 'Describe how auxin causes roots to grow downwards (gravitropism).', marks: 3, markScheme: `• Auxin settles on the lower side of a horizontal root (1).\n• Unlike in shoots, high auxin in roots inhibits cell elongation (1).\n• Upper side elongates more — root bends downwards (positively gravitropic) (1).` },
      { q: 'State three commercial uses of plant hormones.', marks: 3, markScheme: `• Auxins — as weedkillers (selective), rooting powders, tissue culture (1).\n• Gibberellins — end seed dormancy, promote flowering, larger fruits (1).\n• Ethene — ripens fruit during storage/transport (1).` },
      { q: 'Explain why blood glucose monitoring is essential for Type 1 diabetes.', marks: 3, markScheme: `• Insulin is not produced — patient must inject before meals (1).\n• Wrong dose can cause hypoglycaemia (too low — unconsciousness) or hyperglycaemia (too high — long-term damage) (1).\n• Regular measurement with a blood glucose monitor ensures correct insulin doses for food/activity (1).` },
      { q: 'A student ate a large sugary meal. Describe and explain the changes in their blood glucose and insulin over the next 2 hours.', marks: 4, markScheme: `• Blood glucose rises rapidly after the meal (1).\n• Pancreas detects rise and releases insulin (1).\n• Insulin causes liver/muscle cells to take up glucose, storing it as glycogen — blood glucose falls (1).\n• Insulin secretion falls; blood glucose returns to normal level after ~2 hours — negative feedback (1).`, needsDiagram: true },
      { q: 'Describe the role of the pituitary gland.', marks: 3, markScheme: `• "Master gland" controlled by the hypothalamus (1).\n• Secretes many hormones, including FSH, LH, ADH, growth hormone, TSH (1).\n• Many of its hormones affect other glands (e.g. TSH → thyroid, FSH/LH → ovaries/testes) and therefore regulate many body processes (1).` },
      { q: 'Suggest why negative feedback is vital for homeostasis.', marks: 3, markScheme: `• It opposes the change that has occurred, restoring the variable to the set point (1).\n• Prevents large fluctuations which would disrupt enzyme activity and cell function (1).\n• Ensures optimum conditions are maintained despite external changes (1).` },
      { q: 'Compare the nervous and endocrine systems.', marks: 4, markScheme: `• Nervous: impulses are electrical, travel along neurones, very fast, short-lived effects, targeted at specific muscles/glands (1) (1).\n• Endocrine: hormones are chemical messengers, travel in blood, slower but longer-lasting effects, act on target organs with specific receptors (1) (1).` },
      { q: 'Describe one method a doctor can use to diagnose diabetes.', marks: 2, markScheme: `• Urine dipstick or blood test — detects glucose in urine or high blood glucose (1).\n• Fasting blood glucose test or oral glucose tolerance test confirms diagnosis (1).` },
      { q: 'A plant is placed horizontally in darkness. Predict what happens to the root and shoot.', marks: 3, markScheme: `• Shoot grows upwards (negatively gravitropic) as auxin accumulates on lower side and causes more elongation there, bending shoot away from gravity (1).\n• Root grows downwards (positively gravitropic) (1).\n• In roots, auxin inhibits growth on the lower side; upper side elongates more so root bends down (1).` },
    ]
  },

  /* ─────────────────────────────────────────────────────────── 4.6 Inheritance, Variation and Evolution */
  '4.6': {
    name: 'Inheritance, Variation and Evolution',
    questions: [
      { q: 'Define the terms gene, chromosome, DNA and genome.', marks: 4, markScheme: `• Gene — section of DNA coding for a specific protein (1).\n• Chromosome — a long threaded structure of DNA containing many genes (1).\n• DNA — deoxyribonucleic acid, the polymer in a double helix that stores genetic information (1).\n• Genome — the entire genetic material of an organism (1).` },
      { q: 'Describe the structure of the DNA molecule.', marks: 3, markScheme: `• DNA is a double helix of two strands (1).\n• Made up of nucleotides (sugar-phosphate backbone + a base) (1).\n• Four bases: A pairs with T; C pairs with G — complementary base pairing (1).` },
      { q: 'State how many chromosomes are found in a human body cell and a human gamete.', marks: 2, markScheme: `• Body cell — 23 pairs = 46 chromosomes (diploid) (1).\n• Gamete (sperm or egg) — 23 chromosomes (haploid) (1).` },
      { q: 'Compare mitosis and meiosis.', marks: 4, markScheme: `• Mitosis produces 2 genetically identical diploid daughter cells; used for growth and repair (1).\n• Meiosis produces 4 genetically different haploid gametes (1).\n• Mitosis involves one division; meiosis involves two divisions (1).\n• Meiosis introduces variation by independent assortment and crossing over (1).` },
      { q: 'Explain why sexual reproduction leads to genetic variation.', marks: 3, markScheme: `• Gametes are produced by meiosis — each has a unique combination of alleles (1).\n• Fertilisation is random — any sperm can fertilise any egg (1).\n• Offspring inherit half their genes from each parent, producing new combinations of alleles (1).` },
      { q: 'Explain the advantages and disadvantages of asexual reproduction.', marks: 4, markScheme: `• Advantages: only one parent needed (no mate required) (1); faster and more energy efficient; all offspring inherit successful traits (1).\n• Disadvantages: no variation in offspring (1); population is vulnerable to the same disease or environmental change (1).` },
      { q: 'Define allele, phenotype and genotype.', marks: 3, markScheme: `• Allele — different version of a gene (1).\n• Phenotype — the observable characteristics of an organism (1).\n• Genotype — the combination of alleles present for a particular gene (1).` },
      { q: 'Define homozygous and heterozygous, with examples.', marks: 2, markScheme: `• Homozygous — two identical alleles (e.g. BB or bb) (1).\n• Heterozygous — two different alleles (e.g. Bb) (1).` },
      { q: 'Explain dominant and recessive alleles using an example.', marks: 3, markScheme: `• Dominant allele is always expressed when present (represented by a capital letter) (1).\n• Recessive allele is only expressed when both alleles are recessive (lowercase) (1).\n• Example: purple (P) flower dominant over white (p): PP and Pp both purple; pp is white (1).` },
      { q: 'A pea plant cross: Tall (Tt) × tall (Tt). Draw the Punnett square and give phenotype and genotype ratios.', marks: 4, markScheme: `• Gametes: T, t × T, t (1).\n• Punnett:\n     T     t\n T  TT   Tt\n t  Tt   tt\n• Genotypes: 1 TT : 2 Tt : 1 tt (1).\n• Phenotypes: 3 tall : 1 short (1).\n• Probability of short offspring = 1/4 = 25% (1).`, needsDiagram: true },
      { q: 'A tall (Tt) pea plant is crossed with a short (tt) pea plant. What are the expected phenotype proportions in the offspring?', marks: 3, markScheme: `• Gametes: T and t × t only (1).\n• Offspring: 2 Tt (tall) : 2 tt (short) = 1:1 (1).\n• 50% tall : 50% short (1).` },
      { q: 'Describe how cystic fibrosis is inherited.', marks: 4, markScheme: `• CF is caused by a recessive allele (f) (1).\n• Carriers (Ff) are heterozygous — do not show CF but can pass on the allele (1).\n• Only ff (homozygous recessive) individuals have CF (1).\n• Two carrier parents (Ff × Ff) have a 1 in 4 chance of producing an ff child (1).` },
      { q: 'Describe the inheritance of polydactyly.', marks: 3, markScheme: `• Caused by a dominant allele (P) (1).\n• Only one copy needed to produce the phenotype — Pp or PP shows polydactyly (1).\n• Genetic cross Pp × pp gives 50% polydactyly; Pp × Pp gives 75% polydactyly (1).` },
      { q: 'Describe how the sex of a human is determined genetically.', marks: 3, markScheme: `• Females have two X chromosomes (XX) — all egg cells carry an X (1).\n• Males have one X and one Y (XY) — sperm carry either X or Y (1).\n• At fertilisation: X + X = female, X + Y = male — 50:50 chance (1).` },
      { q: 'Draw a Punnett square to show sex inheritance and state the probability of a male child.', marks: 3, markScheme: `• Father XY × mother XX (1).\n• Offspring: XX, XX, XY, XY → 2 XX : 2 XY (1).\n• 50% chance of male (XY), 50% female (XX) (1).`, needsDiagram: true },
      { q: 'Define mutation and describe its effect.', marks: 3, markScheme: `• A random change in the base sequence of DNA (1).\n• Most have little or no effect on the phenotype (neutral) (1).\n• A few cause changes in the protein produced; these can be harmful, neutral or beneficial (basis of evolution) (1).` },
      { q: 'State three causes of mutation.', marks: 3, markScheme: `• Ionising radiation (UV, X-rays, gamma rays) (1).\n• Chemical mutagens (e.g. tar from cigarettes) (1).\n• Spontaneous errors during DNA replication (1).` },
      { q: 'Describe Darwin\'s theory of evolution by natural selection.', marks: 5, markScheme: `• Variation between individuals in a population (1).\n• Competition for resources and not all survive (1).\n• Individuals with traits best suited to environment are more likely to survive and reproduce (1).\n• They pass their alleles to offspring (1).\n• Over many generations, advantageous traits become more common in the population — potentially leading to speciation (1).` },
      { q: 'Explain why Darwin\'s theory was controversial when first published.', marks: 3, markScheme: `• It contradicted religious beliefs about divine creation (1).\n• There was no mechanism of inheritance known at the time (Mendel\'s work not yet recognised) (1).\n• There was no clear evidence of transitional fossils (many have been discovered since) (1).` },
      { q: 'Explain how the work of Mendel supports Darwin\'s theory.', marks: 3, markScheme: `• Mendel\'s work showed that traits are inherited as discrete units (later identified as genes) (1).\n• This provides the mechanism for inheritance that Darwin\'s theory needed (1).\n• Combined with mutation as a source of variation, Darwin\'s theory becomes the modern synthesis (1).` },
      { q: 'Describe how the fossil record supports evolution.', marks: 3, markScheme: `• Shows change in species over geological time (1).\n• Transitional fossils (e.g. Archaeopteryx — reptile/bird) connect modern groups (1).\n• Timing of fossils in rock layers consistent with evolutionary relationships (older forms in deeper layers) (1).` },
      { q: 'Explain why there are gaps in the fossil record.', marks: 3, markScheme: `• Soft-bodied organisms rarely fossilise (need hard parts or preserved conditions) (1).\n• Many fossils have been destroyed by geological processes (erosion, metamorphism) (1).\n• Many remain undiscovered or are in rocks that have not been examined (1).` },
      { q: 'Define speciation.', marks: 3, markScheme: `• The formation of a new species (1).\n• Occurs when populations become isolated (geographically/genetically) (1).\n• Over time, different selection pressures and mutations mean the two populations can no longer interbreed to produce fertile offspring (1).` },
      { q: 'Describe the development of resistance to antibiotics in bacteria using natural selection.', marks: 5, markScheme: `• Random mutations produce bacteria with some resistance (1).\n• When antibiotic is used, non-resistant bacteria die; resistant bacteria survive (1).\n• Resistant bacteria reproduce, passing resistance to offspring (1).\n• Over generations, the resistant strain dominates (1).\n• Example: MRSA resistant to methicillin; spread is a serious hospital problem (1).` },
      { q: 'Describe selective breeding with an example.', marks: 4, markScheme: `• Humans choose individuals with desired traits to breed together (1).\n• Offspring showing the desired trait are bred again — over generations the trait becomes common in the population (1).\n• Example: dairy cows selected for high milk yield; wheat for disease resistance; dogs for specific behaviours (1).\n• Disadvantages: reduced gene pool; inbreeding leads to health problems (1).` },
      { q: 'Describe the stages of genetic engineering to produce insulin-producing bacteria.', marks: 5, markScheme: `• The insulin gene is cut out of a human chromosome using a restriction enzyme (1).\n• A plasmid is cut with the same restriction enzyme (1).\n• The insulin gene is joined into the plasmid using DNA ligase (1).\n• The plasmid is inserted into a bacterium (1).\n• Bacteria multiply in fermenters, producing large amounts of insulin, which is purified (1).` },
      { q: 'Evaluate the use of GM crops.', marks: 6, markScheme: `• Advantages: increased yield, resistance to pests/herbicides/disease (1); improved nutrition (e.g. golden rice with vitamin A) (1); reduced need for pesticides (1).\n• Disadvantages: effects on biodiversity (non-target species may be affected) (1); transfer of genes to wild plants (1); concerns about long-term health effects and cost/accessibility in developing countries (1).` },
      { q: 'Define clone and give one natural and one artificial example.', marks: 3, markScheme: `• A clone is a genetically identical copy of an organism (1).\n• Natural: identical twins form when a fertilised egg divides (1).\n• Artificial: tissue culture of plants; cuttings; embryo transplants; adult cell cloning e.g. Dolly the sheep (1).` },
      { q: 'Describe the process of adult cell cloning (e.g. Dolly the sheep).', marks: 5, markScheme: `• The nucleus of an adult (e.g. udder) cell is removed (1).\n• The nucleus of an unfertilised egg cell is removed (enucleation) (1).\n• The adult cell nucleus is inserted into the empty egg cell (1).\n• Electric shock stimulates the egg to divide and form embryo (1).\n• Embryo is implanted into a surrogate mother (host) — the offspring is a clone of the nucleus donor (1).` },
      { q: 'Explain the Linnaean system of classification.', marks: 3, markScheme: `• Organisms are grouped by similarity in shared features (1).\n• Hierarchical levels: kingdom, phylum, class, order, family, genus, species (1).\n• Binomial system: each organism has a genus and species name (e.g. Homo sapiens) — Latin, italicised (1).` },
      { q: 'Describe the three-domain system proposed by Woese.', marks: 3, markScheme: `• Based on molecular evidence, particularly rRNA sequences (1).\n• Divides life into three domains: Archaea, Bacteria, and Eukaryota (1).\n• Eukaryota includes animals, plants, fungi, protists; Archaea are distinct from bacteria despite superficial similarity (1).` },
      { q: 'Describe an evolutionary tree and explain what it shows.', marks: 3, markScheme: `• A diagram showing how different species are related to each other through common ancestors (1).\n• Branches represent speciation events (1).\n• Closer branches mean more recent common ancestor and greater similarity (1).`, needsDiagram: true },
      { q: 'Describe two possible examples of speciation (geographical isolation).', marks: 3, markScheme: `• A population is separated by a physical barrier (e.g. a river or mountain) (1).\n• Different selection pressures and random mutations in each population (1).\n• Over time, populations become so genetically different they can no longer interbreed — two separate species (e.g. Galapagos finches) (1).` },
      { q: 'Evaluate the ethics of cloning animals like Dolly.', marks: 4, markScheme: `• Benefits: could save endangered species; study genetic diseases; produce animals with desirable traits; produce pharmaceuticals in milk (1).\n• Disadvantages: low success rate (hundreds of attempts to produce Dolly) (1); clones may have health problems, premature aging (1).\n• Ethical concerns: welfare of clones; potential application to humans raises serious moral questions (1).` },
      { q: 'State two factors that cause variation in a population.', marks: 2, markScheme: `• Genetic variation from mutations and sexual reproduction (1).\n• Environmental variation (e.g. diet, exercise, sunlight) (1).` },
      { q: 'A parent with blood group A (IᴬIᴼ) is crossed with a parent of blood group B (IᴮIᴼ). Use a Punnett square to show possible offspring blood groups.', marks: 4, markScheme: `• Punnett:\n      Iᴬ     Iᴼ\n Iᴮ  IᴬIᴮ  IᴮIᴼ\n Iᴼ  IᴬIᴼ  IᴼIᴼ\n• Offspring: IᴬIᴮ (AB), IᴮIᴼ (B), IᴬIᴼ (A), IᴼIᴼ (O) (1 for each correct genotype up to 4).\n• Ratio = 1 A : 1 B : 1 AB : 1 O — 25% chance of each blood group (co-dominance between Iᴬ and Iᴮ; both dominant to Iᴼ).`, needsDiagram: true },
      { q: 'Explain why identical twins have similar appearance but are not always identical in behaviour.', marks: 3, markScheme: `• Identical twins share the same genotype — same genes (1).\n• Phenotype is influenced by both genetics and environment (1).\n• Differences in diet, exercise, life experiences (environment) lead to behavioural and physical differences even with identical DNA (1).` },
      { q: 'State two characteristics of a species.', marks: 2, markScheme: `• Members can interbreed and produce fertile offspring (1).\n• Share a common evolutionary history and key genetic similarities (1).` },
      { q: 'Describe how DNA sequencing technology has changed classification.', marks: 3, markScheme: `• Comparing DNA/base sequences of species shows evolutionary relationships directly (1).\n• Has confirmed many existing classifications and changed others (e.g. some fungi moved, three-domain system) (1).\n• Provides a more objective, molecular basis for classification than physical features alone (1).` },
      { q: 'The fossil record shows that horses evolved from small, multi-toed ancestors to large, single-toed animals. Suggest why.', marks: 4, markScheme: `• Environment changed — from forest to grassland (1).\n• Larger size and longer legs allowed faster running away from predators (1).\n• Single hoof (from multiple toes) suited hard grassland terrain (1).\n• Selection pressures favoured individuals with these traits — allele frequencies changed over millions of years (1).` },
    ]
  },

  /* ─────────────────────────────────────────────────────────── 4.7 Ecology */
  '4.7': {
    name: 'Ecology',
    questions: [
      { q: 'Define "ecosystem" and "habitat".', marks: 2, markScheme: `• Ecosystem — the interaction of a community (living) with the abiotic (non-living) parts of an environment (1).\n• Habitat — the place in which an organism lives (1).` },
      { q: 'State three examples of abiotic factors.', marks: 3, markScheme: `• Light intensity / temperature (1).\n• Moisture level / water availability (1).\n• Soil pH / mineral content / CO₂ for plants / O₂ for aquatic animals / wind intensity and direction (1).` },
      { q: 'State three examples of biotic factors.', marks: 3, markScheme: `• Availability of food (1).\n• New predators arriving (1).\n• New pathogens (1). (Also accept: one species outcompeting another.)` },
      { q: 'Define "interdependence" and give an example.', marks: 3, markScheme: `• Species rely on each other for survival — food, shelter, pollination, seed dispersal, etc. (1).\n• Example: bees pollinate flowering plants and obtain nectar; without bees many plants could not reproduce (1).\n• Remove or add a species and the community is disrupted — stable communities rely on balanced interdependence (1).` },
      { q: 'State what is meant by the term "community" and "population" with examples.', marks: 2, markScheme: `• Community — all the populations of different species living in the same habitat (e.g. all plants, insects, birds in a pond) (1).\n• Population — all the individuals of one species in a habitat (e.g. all trout in a lake) (1).` },
      { q: 'Describe the transfer of biomass in a food chain.', marks: 3, markScheme: `• Producers (plants) make biomass by photosynthesis (1).\n• Primary consumers eat producers; secondary consumers eat primary consumers (1).\n• Only ~10% of biomass is transferred to each next trophic level; the rest is lost in respiration, faeces, waste, or not eaten (1).` },
      { q: 'Describe how you would estimate the population of a plant species in a field using quadrats.', marks: 5, markScheme: `• Measure the total area of the field (1).\n• Place a 1 m × 1 m quadrat at random positions (use random numbers for coordinates) (1).\n• Count the number of individuals of the species in each quadrat (1).\n• Take at least 10 samples and calculate the mean per m² (1).\n• Multiply mean density by total area to estimate the population (1).`, needsDiagram: true },
      { q: 'Describe how you would use a transect to study how a plant community changes across a habitat.', marks: 4, markScheme: `• Run a tape measure along a line (transect) across the habitat (1).\n• Place quadrats at regular intervals along the line (e.g. every 2 m) (1).\n• Count / estimate % cover of species in each quadrat (1).\n• Plot kite diagram or bar chart to show how abundance changes with distance — reveals relationships with abiotic factors (e.g. light, moisture) (1).`, needsDiagram: true },
      { q: 'Describe the water cycle.', marks: 5, markScheme: `• Water evaporates from oceans, lakes, rivers and is transpired from plants (1).\n• Water vapour rises and condenses into clouds (1).\n• Precipitation as rain/snow returns water to land (1).\n• Water flows through rivers back to the sea, percolates into groundwater, or is taken up by organisms (1).\n• Cycle is powered by the sun and essential for life (1).` },
      { q: 'Describe the role of photosynthesis, respiration and combustion in the carbon cycle.', marks: 4, markScheme: `• Photosynthesis: producers remove CO₂ from atmosphere → glucose → biomass (1).\n• Respiration: all organisms release CO₂ back to atmosphere from glucose (1).\n• Combustion: burning fuels (wood, fossil fuels) releases stored carbon as CO₂ (1).\n• Decomposition returns carbon from dead organisms to soil/atmosphere (1).`, needsDiagram: true },
      { q: 'Explain the role of decomposers in ecosystems.', marks: 3, markScheme: `• Decomposers (bacteria and fungi) break down dead organisms and waste (1).\n• They release nutrients (nitrogen as ammonium/nitrate, phosphates) back to soil (1).\n• These nutrients are reabsorbed by plants; recycling maintains ecosystem fertility (1).` },
      { q: 'State three conditions that speed up decomposition.', marks: 3, markScheme: `• Warm temperature (up to enzyme optimum) (1).\n• Moist (water for microbial activity) (1).\n• Aerobic (oxygen for respiration of decomposers) (1).` },
      { q: 'Describe the role of bacteria in the nitrogen cycle.', marks: 4, markScheme: `• Nitrogen-fixing bacteria (free-living or in root nodules of legumes) convert N₂ to ammonium (1).\n• Decomposers break down proteins to ammonium (1).\n• Nitrifying bacteria convert ammonium to nitrates (usable by plants) (1).\n• Denitrifying bacteria (in waterlogged soil) convert nitrates back to N₂ — removes nitrogen from soil (1).` },
      { q: 'Explain how deforestation affects the environment.', marks: 4, markScheme: `• Removes trees that absorb CO₂; less photosynthesis (1).\n• Burning releases stored carbon as CO₂, adding to greenhouse gases (1).\n• Reduces biodiversity — loss of habitats (1).\n• Causes soil erosion and disrupts water cycle and rainfall patterns (1).` },
      { q: 'Explain how human activities contribute to global warming.', marks: 4, markScheme: `• Burning fossil fuels releases CO₂ (1).\n• Deforestation reduces CO₂ uptake (1).\n• Livestock farming (especially cattle) and paddy fields produce methane (CH₄) (1).\n• Increased greenhouse gas concentration traps more infrared, warming the atmosphere (1).` },
      { q: 'Describe four consequences of global warming.', marks: 4, markScheme: `• Melting polar ice caps, rising sea levels and flooding of coastal land (1).\n• Loss of habitats (e.g. polar bears, coral reefs) and altered species distribution (1).\n• More extreme weather events (droughts, storms) (1).\n• Effects on agriculture — some crops may fail; new pests may migrate (1).` },
      { q: 'Explain why peat bogs are important to the carbon cycle.', marks: 3, markScheme: `• Peat bogs store huge amounts of carbon as partially decayed plant material (anaerobic waterlogged conditions slow decomposition) (1).\n• Draining and burning peat releases stored CO₂ to the atmosphere, contributing to global warming (1).\n• Destroying peat bogs also destroys unique habitats, reducing biodiversity (1).` },
      { q: 'Describe three reasons why biodiversity is important.', marks: 3, markScheme: `• Ecosystem services — pollination, clean air/water, nutrient recycling, climate regulation (1).\n• Medicinal/scientific — many drugs come from plants/microbes; future discoveries depend on diversity (1).\n• Resilience — diverse ecosystems are more stable and able to adapt to environmental change (1).` },
      { q: 'State three ways we can maintain biodiversity.', marks: 3, markScheme: `• Breeding programmes for endangered species (1).\n• Protected reserves, regenerating hedgerows / field margins on farmland (1).\n• Reducing deforestation and CO₂ emissions; recycling resources (1).` },
      { q: 'Describe how an indicator species is used to monitor air pollution.', marks: 3, markScheme: `• Indicator species are sensitive to pollution levels (1).\n• Lichens indicate clean air — many species grow on trees and stones in unpolluted areas (1).\n• Absence of lichens and presence of pollution-tolerant species (e.g. crustose lichens only) suggests high SO₂ pollution (1).` },
      { q: 'Describe how an indicator species is used to monitor water pollution.', marks: 3, markScheme: `• Mayfly larvae require high O₂ levels — their presence indicates clean water (1).\n• Sludgeworms and rat-tailed maggots tolerate low O₂ — their presence indicates polluted, organically-rich water (1).\n• A Biotic Index (e.g. BMWP) is used to categorise water quality based on species present (1).` },
      { q: 'Describe a pyramid of biomass and explain its shape.', marks: 4, markScheme: `• Shows the dry mass per unit area at each trophic level (1).\n• Producers at the bottom (widest); each level above narrower (1).\n• Because ~90% of biomass is lost as heat (respiration), faeces, and inedible parts (1).\n• Only ~10% efficiency explains shape and why food chains rarely exceed 4–5 links (1).`, needsDiagram: true },
      { q: 'Calculate the efficiency of biomass transfer if 10 000 kJ of producers support 800 kJ of primary consumers.', marks: 2, markScheme: `• Efficiency = (output ÷ input) × 100 = (800 ÷ 10 000) × 100 (1).\n• = 8% (1).` },
      { q: 'Describe the consequences of overfishing.', marks: 4, markScheme: `• Reduces fish stocks below levels needed to support the population (1).\n• Some species may collapse (e.g. Grand Banks cod) and take decades to recover (1).\n• Reduces biodiversity (by-catch of non-target species also affected) (1).\n• Managed by quotas, net mesh sizes and protected areas to restore stocks (1).` },
      { q: 'Explain why food chains are usually no longer than 4–5 trophic levels.', marks: 3, markScheme: `• About 90% of energy/biomass is lost between trophic levels (1).\n• After 4–5 levels, not enough energy remains to support a population (1).\n• Top predators need very large hunting ranges because of the low biomass at their level (1).` },
      { q: 'Describe the effects of using fertilisers on waterways.', marks: 4, markScheme: `• Fertiliser run-off adds nitrates and phosphates to water (1).\n• Algae grow rapidly (algal bloom) — blocks sunlight to aquatic plants (1).\n• Plants die and are decomposed by bacteria, using up O₂ (1).\n• Low O₂ kills fish and other organisms — process called eutrophication (1).`, needsDiagram: true },
      { q: 'Explain how fish farming can be made more sustainable.', marks: 4, markScheme: `• Use plant-based feed (e.g. soy) rather than wild fish for feed (1).\n• Treat waste from farms to prevent pollution of wild waters (1).\n• Control diseases to reduce reliance on antibiotics (1).\n• Location of farms away from wild fish migration routes to reduce ecological disruption (1).` },
      { q: 'Describe how biogas is produced and evaluate its use as a fuel.', marks: 4, markScheme: `• Bacteria anaerobically break down plant/animal waste in a biogas generator (1).\n• Produces methane-rich gas, used for cooking, heating, electricity (1).\n• Advantages: uses waste, reduces fossil fuel use, slurry remains as fertiliser (1).\n• Disadvantages: needs steady waste supply, leaks of methane could harm environment, capital cost of building generator (1).` },
      { q: 'Describe two ways humans can maintain hedgerow and field-margin biodiversity on farmland.', marks: 3, markScheme: `• Maintain hedgerows rather than removing them — provides habitat, nesting sites, food (1).\n• Leave strips at field margins (wildflowers) — supports pollinators and predators of pests (1).\n• These corridors link habitats, allowing species to move and preventing fragmented populations (1).` },
      { q: 'Explain why intensive farming often reduces biodiversity.', marks: 3, markScheme: `• Large monoculture fields replace diverse habitats (1).\n• Pesticides and herbicides kill non-target species (1).\n• Removal of hedgerows destroys habitats and reduces habitats for wildlife (1).` },
      { q: 'Evaluate sustainable vs intensive farming.', marks: 6, markScheme: `• Intensive: high yields, low cost per item, feeds large populations (1). Disadvantages: habitat loss, pollution, animal welfare concerns (1).\n• Sustainable/organic: better animal welfare, lower pesticide/ fertiliser use, higher biodiversity (1). Disadvantages: lower yields, higher cost per item, more land needed (1).\n• Balance: many countries move toward "sustainable intensification" — efficient use of land combined with environmental protection (1).\n• Conclusion: depends on priorities — food security, environmental protection, economics (1).` },
      { q: 'Describe the effects on a woodland ecosystem of introducing a non-native squirrel (e.g. grey squirrel in the UK).', marks: 4, markScheme: `• Grey squirrels outcompete red squirrels for food and habitat (1).\n• Spread squirrelpox virus, to which they are immune but red squirrels are not (1).\n• Red squirrel populations decline; biodiversity reduced (1).\n• Conservation responses: culling greys, protecting red squirrel reserves, monitoring populations (1).` },
      { q: 'Describe three impacts of building a large dam on a river ecosystem.', marks: 3, markScheme: `• Floods large upstream areas — loss of terrestrial habitat and displacement of animals (1).\n• Prevents migration of fish (e.g. salmon upstream) disrupting food chains (1).\n• Changes water flow, temperature and sediment downstream, altering river habitats and species composition (1).` },
      { q: 'Describe how to carry out an investigation comparing the number of dandelions in a field and in a lawn.', marks: 5, markScheme: `• Choose a 1 m × 1 m quadrat and place at random positions (use random numbers for coordinates) (1).\n• In each area, record the number of dandelions in at least 10 quadrats (1).\n• Calculate the mean per m² in each area (1).\n• Compare means statistically (1).\n• Consider abiotic factors: light, moisture, grass height, pH — differences may reflect these (1).` },
      { q: 'A predator-prey graph shows oscillating populations of lynx and hare. Explain the pattern.', marks: 4, markScheme: `• When hare numbers are high, lynx have abundant food and reproduce more — lynx numbers rise (1).\n• High lynx numbers eat many hares — hare population falls (1).\n• Less food → lynx population falls (1).\n• Fewer predators allow hare population to recover — cycle repeats (1).`, needsDiagram: true },
      { q: 'Explain why some conservation programmes for endangered species are unsuccessful.', marks: 3, markScheme: `• Low genetic variation (inbreeding) in small populations — vulnerable to disease and reduced fertility (1).\n• Lack of suitable habitat for reintroduction (1).\n• Social/political issues — local communities may not support conservation; poaching, illegal trade (1).` },
      { q: 'Describe how you could calculate the percentage cover of a species in a quadrat.', marks: 3, markScheme: `• Divide the 1 m × 1 m quadrat into 100 squares (10 × 10 grid) (1).\n• Count the number of squares in which the species is present (1).\n• Each square = 1% cover; total squares = % cover (1).` },
      { q: 'Compare a pyramid of numbers with a pyramid of biomass.', marks: 3, markScheme: `• Pyramid of numbers shows the number of organisms at each level; may be inverted (e.g. one oak tree supports many caterpillars) (1).\n• Pyramid of biomass shows the dry mass at each level — almost always a standard pyramid shape (1).\n• Pyramid of biomass is more accurate as it accounts for size of organisms and avoids odd inversions (1).` },
      { q: 'State three factors affecting global food security.', marks: 3, markScheme: `• Increasing human population (1).\n• Climate change affecting crop yields (1).\n• New pests and pathogens / cost of inputs / conflict disrupting farming / changing diets (any 1 more).` },
      { q: 'Explain why vegetarian diets are more energy-efficient than meat-based diets.', marks: 3, markScheme: `• Eating plants = one trophic level transfer (sunlight → plants → humans), ~10% efficiency (1).\n• Eating meat = two transfers (sunlight → plants → animals → humans), ~1% efficiency (1).\n• Feeding crops directly to humans feeds ~10× more people per hectare (1).` },
      { q: 'Evaluate the use of captive breeding programmes for endangered species.', marks: 6, markScheme: `• Advantages: can save species on the brink of extinction; genetic material preserved; education and public engagement in zoos (1). Reintroduction of animals increases wild populations (e.g. California condor, Arabian oryx) (1).\n• Disadvantages: captive conditions can cause behavioural problems — animals may struggle to survive in wild (1). Small gene pool leads to inbreeding and health problems (1).\n• Alternative/supplementary approaches: habitat protection, anti-poaching, community engagement, ecological restoration (1).\n• Conclusion: captive breeding alone rarely saves a species — must be combined with habitat protection and sustainable management (1).` },
    ]
  },
};

if (typeof window !== 'undefined') window.BIOLOGY_AQA_GCSE_PRACTICE = BIOLOGY_AQA_GCSE_PRACTICE;
